def select_action(obs: np.ndarray) -> int:
    ball_x = int(obs[49])
    ball_y = int(obs[54])
    paddle_y = int(obs[51])

    # Estimate ball vertical velocity from previous frame (stored in global)
    if not hasattr(select_action, "prev_ball_y"):
        select_action.prev_ball_y = ball_y
        select_action.ball_direction = 1
    else:
        dy = ball_y - select_action.prev_ball_y
        if dy > 0:
            select_action.ball_direction = 1
        elif dy < 0:
            select_action.ball_direction = -1
        select_action.prev_ball_y = ball_y

    # Predict intercept y at player paddle x (160)
    steps_to_reach = (160 - ball_x) // 4  # ball moves ~4 pixels per frame in x
    if steps_to_reach <= 0:
        target_y = ball_y
    else:
        target_y = ball_y + select_action.ball_direction * 3 * steps_to_reach

    # Simulate wall bounces
    while target_y < 17 or target_y > 194:
        if target_y < 17:
            target_y = 34 - target_y
        else:
            target_y = 388 - target_y

    # Clamp to paddle range
    target_y = max(34, min(194, target_y))

    dead_zone = 5
    if target_y < paddle_y - dead_zone:
        return 2
    elif target_y > paddle_y + dead_zone:
        return 3
    return 0
